CREATE TABLE IF NOT EXISTS users (telegram_id BIGINT PRIMARY KEY, first_name TEXT, last_name TEXT, username TEXT, photo_url TEXT, freelancer_id UUID NOT NULL DEFAULT gen_random_uuid(), client_id UUID NOT NULL DEFAULT gen_random_uuid(), balance NUMERIC(18,2) NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE UNIQUE INDEX IF NOT EXISTS users_freelancer_id_idx ON users (freelancer_id);
CREATE UNIQUE INDEX IF NOT EXISTS users_client_id_idx ON users (client_id);
CREATE TABLE IF NOT EXISTS orders (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), owner_id BIGINT NOT NULL REFERENCES users (telegram_id) ON DELETE CASCADE, title TEXT NOT NULL, short_description TEXT, description TEXT, category TEXT, deadline_days INTEGER NOT NULL DEFAULT 1, image_data_url TEXT, price NUMERIC(18,2) NOT NULL DEFAULT 0, currency TEXT NOT NULL DEFAULT 'USDT', status TEXT NOT NULL DEFAULT 'active', moderation_status TEXT NOT NULL DEFAULT 'pending', admin_note TEXT, funds_reserved BOOLEAN NOT NULL DEFAULT false, assigned_freelancer_id BIGINT REFERENCES users (telegram_id), views INTEGER NOT NULL DEFAULT 0, completed_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS orders_owner_idx ON orders (owner_id);
CREATE INDEX IF NOT EXISTS orders_moderation_idx ON orders (moderation_status);
CREATE TABLE IF NOT EXISTS responses (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), order_id UUID NOT NULL REFERENCES orders (id) ON DELETE CASCADE, freelancer_id BIGINT NOT NULL REFERENCES users (telegram_id) ON DELETE CASCADE, status TEXT NOT NULL DEFAULT 'pending', created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE UNIQUE INDEX IF NOT EXISTS responses_order_freelancer_idx ON responses (order_id, freelancer_id);
CREATE INDEX IF NOT EXISTS responses_freelancer_idx ON responses (freelancer_id);
CREATE TABLE IF NOT EXISTS freelancer_profiles (telegram_id BIGINT PRIMARY KEY REFERENCES users (telegram_id) ON DELETE CASCADE, headline TEXT, about TEXT, skills TEXT, hourly_rate NUMERIC(18,2), currency TEXT NOT NULL DEFAULT 'USDT', portfolio_url TEXT, moderation_status TEXT NOT NULL DEFAULT 'pending', admin_note TEXT, updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS deposits (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), telegram_id BIGINT NOT NULL REFERENCES users (telegram_id) ON DELETE CASCADE, track_id TEXT UNIQUE, amount NUMERIC(18,2) NOT NULL, currency TEXT NOT NULL DEFAULT 'USDT', status TEXT NOT NULL DEFAULT 'pending', payment_url TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS withdrawals (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), telegram_id BIGINT NOT NULL REFERENCES users (telegram_id) ON DELETE CASCADE, track_id TEXT, amount NUMERIC(18,2) NOT NULL, currency TEXT NOT NULL DEFAULT 'USDT', address TEXT NOT NULL, network TEXT, status TEXT NOT NULL DEFAULT 'pending', admin_note TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
